    @Test
    @DisplayName("TC01: wrap(Writer) with empty input produces no output and does not write any characters (loop-0, branch-false)")
    public void test_TC01() throws Exception {
        // empty input means reader.read() returns -1 immediately → no write calls
        WordWrap.Builder b = WordWrap.from(new java.io.BufferedReader(new StringReader("")));
        StringWriter out = new StringWriter();
        b.wrap(out);
        assertEquals("", out.toString());
    }

    @Test
    @DisplayName("TC02: wrap(Writer) with single short word under maxWidth writes the word without newline (loop-N, branch-false)")
    public void test_TC02() throws Exception {
