    public void test_TC04() throws Exception {
        // word length 10 > maxWidth 3, breakWords true, insertHyphens false triggers broken-word branch without hyphens
        WordWrap.Builder b = WordWrap.from("abcdefghij")
            .maxWidth(3)
            .insertHyphens(false)
            .breakWords(true);
        StringWriter out = new StringWriter();
        b.wrap(out);
        assertEquals("abc\ndef\nghi\nj", out.toString());
    }

